import { MyOrdersItemPropsView, STATUS_COLORS } from './models';

const MyOrdersCashbackView: FC<MyOrdersItemPropsView> = ({
  handleGoBack,
  myOrders,
  emptyImage,
  formatDate,
  isLoading,
  isError,
  modalizeRefFilters,
  handleOpenFilters,
  handleDetailsOrders,
  handleRefresh,
  filterGroups,
  isRefreshing,
  skeletonCount,
  screenWidth,
}) => {
  return (
    <BasicScreen
      title="Meus pedidos"
      errorButtonOnPress={() => {}}
      hasScroll
      leftIconOnPress={handleGoBack}
      rightIcon="icon-filter-settings"
      rightIconOnPress={handleOpenFilters}
      hasRightIcon={!!myOrders.length}
      scrollViewProps={{
        refreshControl: (
