     1→import { TransactionType, MyOrdersDetailProps } from "./Models";
     2→
     3→export type TransactionGainType = 'CARD' | 'TAG' | 'CASHBACK';
     4→
     5→export const getTransactionGainType = (transaction: MyOrdersDetailProps['transaction']): TransactionGainType => {
     6→  if (!transaction) return 'CARD';
     7→  
     8→  const provider = transaction.details?.provider?.toLowerCase() || '';
     9→  
    10→  if (provider.includes('cashback')) {
    11→    return 'CASHBACK';
    12→  }
    13→  
    14→  const icon = transaction.icon?.toLowerCase() || '';
    15→  const description = transaction.description?.toLowerCase() || '';
    16→  
    17→  const tagIndicators = ['tag', 'pedágio', 'pedagio', 'estacionamento', 'abastecimento', 'abastece', 'drive', 'lava', 'rápido'];
    18→  
    19→  const isTag = tagIndicators.some(indicator => 
    20→    icon.includes(indicator) || 
    21→    description.includes(indicator) || 
    22→    provider.includes(indicator)
    23→  );
    24→  
    25→  return isTag ? 'TAG' : 'CARD';
    26→};
    27→
    28→export const getFormattedPointsValue = (amount: number, type: TransactionType): string => {
    29→  const prefix = (type === 'CREDIT' || type === 'REFUNDED') ? '+ ' : '- ';
    30→  const label = Math.abs(amount) === 1 ? 'ponto' : 'pontos';
    31→  return `${prefix}${Math.abs(amount).toLocaleString('pt-BR')} ${label}`;
    32→};
    33→
    34→export const getFormattedHighlightText = (date: string, gainType: TransactionGainType, moment: any): string => {
    35→  const transactionDate = moment(date);
    36→  const day = transactionDate.format('DD');
    37→  const month = transactionDate.format('MMM').toLowerCase();
    38→  const year = transactionDate.format('YYYY');
    39→  const time = transactionDate.format('HH:mm');
    40→  
    41→  return `Pedido feito em ${day} ${month} ${year} às ${time}`;
    42→};
    43→
    44→export const getFormattedPointsValueForMarketplace = (valuePoints: number): string => {
    45→  const absValue = Math.abs(valuePoints);
    46→  const label = absValue === 1 ? 'ponto' : 'pontos';
    47→  return `${absValue.toLocaleString('pt-BR')} ${label}`;
    48→};
    49→
    50→export const getPaymentTypeLabel = (paymentType: string): string => {
    51→  const labels: Record<string, string> = {
    52→    POINTS: 'Pontos',
    53→    CARD: 'Cartão',
    54→    PIX: 'PIX',
    55→  };
    56→  return labels[paymentType] || paymentType;
    57→};
    58→
    59→export const getMarketplaceTitle = (transaction: MyOrdersDetailProps['transaction']): string | null => {
    60→  if (!transaction?.marketplace?.orders) return null;
    61→
    62→  const allItems: Array<{ name: string }> = [];
    63→  transaction.marketplace.orders.forEach(order => {
    64→    if (order.items) {
    65→      allItems.push(...order.items);
    66→    }
    67→  });
    68→
